const data = $input.first().json;
const cliente = data.cliente_nombre || 'Cliente';
const clienteEmail = data.cliente_email;
const servicios = data.servicios || [];
const notas = data.notas || '';

// Calcular totales
let subtotal = 0;
servicios.forEach(s => { subtotal += s.precio; });
const descuento = subtotal > 2000 ? 0.05 : 0;
const montoDescuento = Math.round(subtotal * descuento);
const total = subtotal - montoDescuento;

// Fechas
const hoy = new Date();
const vence = new Date(hoy);
vence.setDate(vence.getDate() + 15);
const formatDate = (d) => d.toLocaleDateString('es-MX',{year:'numeric',month:'long',day:'numeric'});
const fechaCot = formatDate(hoy);
const fechaVence = formatDate(vence);

// Tabla de servicios HTML
const filasServicios = servicios.map(s =>
  `<tr><td style='padding:10px 12px;border-bottom:1px solid #e2e8f0;font-size:14px;color:#334155'>${s.nombre}</td><td style='padding:10px 12px;border-bottom:1px solid #e2e8f0;font-size:14px;color:#334155;text-align:right;font-weight:600'>$${s.precio.toLocaleString()}</td></tr>`
).join('');

const descuentoRow = descuento > 0 ? `<tr><td style='padding:10px 12px;font-size:14px;color:#22c55e'>Descuento (5% por total > $2,000)</td><td style='padding:10px 12px;font-size:14px;color:#22c55e;text-align:right;font-weight:600'>-$${montoDescuento.toLocaleString()}</td></tr>` : '';

const html = `<div style='font-family:Arial,sans-serif;max-width:640px;margin:0 auto;background:#f8fafc;padding:24px'>
<div style='background:white;border-radius:12px;padding:32px;box-shadow:0 1px 3px rgba(0,0,0,.1)'>
<div style='display:flex;align-items:center;justify-content:space-between;margin-bottom:28px'>
<div><h1 style='margin:0;font-size:22px;color:#1e293b'>Cotización de Servicios</h1><p style='margin:4px 0 0;font-size:14px;color:#64748b'>Luis Moreno — Automatización para Negocios</p></div>
<div style='text-align:right'><div style='font-size:12px;color:#64748b'>Fecha: ${fechaCot}</div><div style='font-size:12px;color:#64748b'>Válida hasta: ${fechaVence}</div></div>
</div>

<div style='background:#f0f9ff;border:1px solid #bae6fd;border-radius:8px;padding:16px;margin-bottom:24px'>
<div style='font-size:13px;color:#64748b;margin-bottom:4px'>Preparado para</div>
<div style='font-size:16px;font-weight:700;color:#1e293b'>${cliente}</div>
<div style='font-size:13px;color:#64748b'>${clienteEmail}</div>
</div>

<table style='width:100%;border-collapse:collapse;margin-bottom:8px'>
<thead><tr><th style='padding:10px 12px;text-align:left;font-size:12px;color:#64748b;text-transform:uppercase;letter-spacing:0.05em;border-bottom:2px solid #e2e8f0'>Servicio</th><th style='padding:10px 12px;text-align:right;font-size:12px;color:#64748b;text-transform:uppercase;letter-spacing:0.05em;border-bottom:2px solid #e2e8f0'>Precio</th></tr></thead>
<tbody>${filasServicios}</tbody>
</table>

${descuentoRow}

<div style='background:#1e293b;border-radius:8px;padding:16px 20px;display:flex;justify-content:space-between;align-items:center;margin-top:16px'>
<span style='font-size:16px;font-weight:600;color:#e2e8f0'>Total</span>
<span style='font-size:24px;font-weight:800;color:#ffffff'>$${total.toLocaleString()}</span>
</div>

${notas ? `<div style='margin-top:20px;padding:16px;background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px'><div style='font-size:13px;font-weight:600;color:#64748b;margin-bottom:6px'>Notas adicionales</div><div style='font-size:14px;color:#334155;line-height:1.6'>${notas}</div></div>` : ''}

<div style='margin-top:24px;text-align:center'><a href='https://calendly.com/luismorenoai' style='display:inline-block;background:#2E7BF6;color:white;padding:12px 28px;border-radius:8px;text-decoration:none;font-weight:700;font-size:15px'>Agendar Llamada para Iniciar →</a></div>

<div style='margin-top:24px;padding-top:16px;border-top:1px solid #e2e8f0;font-size:12px;color:#94a3b8;text-align:center'>Esta cotización es válida por 15 días. Precios en USD.</div>
</div></div>`;

return [{json:{cliente,clienteEmail,servicios,subtotal,descuento:montoDescuento,total,notas,html,
  asuntoCliente:`Tu cotización de servicios — Luis Moreno`,
  asuntoLuis:`[COTIZACIÓN ENVIADA] ${cliente} — $${total.toLocaleString()}`
}}];
